// ── Analytics View ────────────────────────────────────────────────────────────
function AnalyticsView({ jobs }) {
  const counts = jobs.reduce((acc, j) => { acc[j.status] = (acc[j.status] || 0) + 1; return acc; }, {});
  const total = jobs.length;
  const responseRate = total > 0 ? Math.round(((counts.Interview || 0) + (counts.Offer || 0)) / total * 100) : 0;
  const offerRate = total > 0 ? Math.round((counts.Offer || 0) / total * 100) : 0;
  const today = new Date().toISOString().split('T')[0];
  const overdueCount = jobs.filter(j => j.followUpDate && j.followUpDate <= today && j.status !== 'Rejected').length;

  const byMonth = {};
  jobs.forEach(j => {
    if (!j.date) return;
    const month = j.date.substring(0, 7);
    byMonth[month] = (byMonth[month] || 0) + 1;
  });

  return (
    <div className="analytics">
      <div className="analytics-top">
        <div className="analytics-card">
          <div className="analytics-card-title">Breakdown</div>
          {total > 0 ? <DonutChart counts={counts} /> : <div className="chart-empty">No data yet</div>}
        </div>

        <div className="analytics-card">
          <div className="analytics-card-title">Key Metrics</div>
          <div className="metrics-grid">
            {[
              { val: total,         label: 'Total',       color: '#4A9EFF' },
              { val: `${responseRate}%`, label: 'Response Rate', color: '#F5A623' },
              { val: `${offerRate}%`,    label: 'Offer Rate',    color: '#50E3A4' },
              { val: counts.Interview || 0, label: 'Interviews',  color: '#F5A623' },
              { val: counts.Rejected  || 0, label: 'Rejections',  color: '#FF5A5A' },
              { val: overdueCount,   label: 'Follow-ups Due', color: overdueCount > 0 ? '#FF5A5A' : 'var(--text2)' },
            ].map(({ val, label, color }) => (
              <div key={label} className="metric-card">
                <div className="metric-val" style={{ color }}>{val}</div>
                <div className="metric-label">{label}</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="analytics-card">
        <div className="analytics-card-title">Monthly Activity</div>
        <BarChart byMonth={byMonth} />
      </div>

      <div className="analytics-card">
        <div className="analytics-card-title">Application Funnel</div>
        <div className="funnel">
          {[
            { label: 'Applied',       key: 'Applied',   color: '#4A9EFF' },
            { label: 'Got Interview', key: 'Interview', color: '#F5A623' },
            { label: 'Received Offer',key: 'Offer',     color: '#50E3A4' },
          ].map(({ label, key, color }) => {
            const count = counts[key] || 0;
            const pct   = total > 0 ? (count / total) * 100 : 0;
            return (
              <div key={key} className="funnel-row">
                <div className="funnel-label">{label}</div>
                <div className="funnel-track">
                  <div className="funnel-fill" style={{ width: `${Math.max(pct, pct > 0 ? 2 : 0)}%`, background: color }}/>
                </div>
                <div className="funnel-stat">
                  <span style={{ color, fontWeight: 700 }}>{count}</span>
                  <span className="funnel-pct"> ({Math.round(pct)}%)</span>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// ── Main App ──────────────────────────────────────────────────────────────────
export default function App() {
  const [gapiReady,  setGapiReady]  = useState(false);
  const [gisReady,   setGisReady]   = useState(false);
  const [isSignedIn, setIsSignedIn] = useState(false);
  const [tokenClient,setTokenClient]= useState(null);
  const [jobs,       setJobs]       = useState([]);
  const [loading,    setLoading]    = useState(false);
  const [progress,   setProgress]   = useState({ step: '', current: 0, total: 0 });
  const [filter,     setFilter]     = useState('All');
  const [sortBy,     setSortBy]     = useState('date');
  const [claudeKey,  setClaudeKey]  = useState('');
  const [keyInput,   setKeyInput]   = useState('');
  const [error,      setError]      = useState('');
  const [searchQuery,setSearchQuery]= useState('');
  const [theme,      setTheme]      = useState(() => localStorage.getItem('jt-theme') || 'dark');
  const [view,       setView]       = useState('table');
  const [showAddModal, setShowAddModal] = useState(false);
  const [selectedJob,  setSelectedJob]  = useState(null);

  // Chat
  const [chatOpen,    setChatOpen]    = useState(false);
  const [chatMessages,setChatMessages]= useState([
    { role: 'assistant', text: "Hi! I'm your job search assistant. Ask me anything about your applications — like \"how many rejections do I have?\" or \"which companies haven't responded?\"" }
  ]);
  const [chatInput,   setChatInput]   = useState('');
  const [chatLoading, setChatLoading] = useState(false);
  const chatEndRef  = useRef(null);
  const claudeKeyRef= useRef('');

  // ── Persist & load ──────────────────────────────────────────────────────────
  useEffect(() => {
    const saved = localStorage.getItem('jt-jobs');
    if (saved) { try { setJobs(JSON.parse(saved)); } catch(e) {} }
  }, []);

  useEffect(() => {
    localStorage.setItem('jt-jobs', JSON.stringify(jobs));
  }, [jobs]);

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('jt-theme', theme);
  }, [theme]);

  useEffect(() => { chatEndRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [chatMessages]);

  // ── Load Google APIs ────────────────────────────────────────────────────────
  useEffect(() => {
    const s1 = document.createElement('script');
    s1.src = 'https://apis.google.com/js/api.js';
    s1.onload = () => window.gapi.load('client', async () => {
      await window.gapi.client.init({ discoveryDocs: ['https://www.googleapis.com/discovery/v1/apis/gmail/v1/rest'] });
      setGapiReady(true);
    });
    document.body.appendChild(s1);
    const s2 = document.createElement('script');
    s2.src = 'https://accounts.google.com/gsi/client';
    s2.onload = () => setGisReady(true);
    document.body.appendChild(s2);
  }, []);

  useEffect(() => {
    if (!gapiReady || !gisReady) return;
    const tc = window.google.accounts.oauth2.initTokenClient({
      client_id: GOOGLE_CLIENT_ID, scope: SCOPES,
      callback: resp => {
        if (resp.error) { setError('OAuth error: ' + resp.error); return; }
        setIsSignedIn(true);
      },
    });
    setTokenClient(tc);
  }, [gapiReady, gisReady]);

  // ── Auth ────────────────────────────────────────────────────────────────────
  const signIn = () => {
    const key = keyInput.trim();
    if (!key) { setError('Please enter your Anthropic API key first.'); return; }
    setClaudeKey(key); claudeKeyRef.current = key;
    tokenClient?.requestAccessToken({ prompt: '' });
  };

  const signOut = () => {
    const token = window.gapi.client.getToken();
    if (token) window.google.accounts.oauth2.revoke(token.access_token);
    window.gapi.client.setToken('');
    setIsSignedIn(false);
  };

  // ── Jobs CRUD ───────────────────────────────────────────────────────────────
  const addJobManually = job => setJobs(prev => [job, ...prev]);

  const updateJob = useCallback((id, updates) => {
    setJobs(prev => prev.map(j => j.id === id ? { ...j, ...updates } : j));
    setSelectedJob(prev => prev?.id === id ? { ...prev, ...updates } : prev);
  }, []);

  const deleteJob = useCallback(id => {
    setJobs(prev => prev.filter(j => j.id !== id));
  }, []);

  // ── Fetch & Analyze ─────────────────────────────────────────────────────────
  const fetchAndAnalyze = useCallback(async () => {
    const activeKey = claudeKeyRef.current || claudeKey;
    if (!activeKey) { setError('API key missing.'); return; }
    setLoading(true); setError(''); setJobs([]); localStorage.removeItem('jt-jobs');

    try {
      setProgress({ step: 'Searching Gmail for job emails…', current: 0, total: 0 });

      const queries = [
        'subject:(application received OR thank you for applying OR we received your application)',
        'subject:(interview OR phone screen OR technical assessment OR video interview OR hiring assessment)',
        'subject:(offer letter OR job offer OR pleased to offer OR congratulations)',
        'subject:(unfortunately OR not moving forward OR other candidates OR not selected OR decided not)',
        'subject:(your application OR application update OR application status OR application submitted)',
        'from:(workday) OR from:(myworkdayjobs.com)',
        'from:(greenhouse.io) OR from:(lever.co)',
        'from:(linkedin.com) subject:application',
        'from:(indeed.com) OR from:(ziprecruiter.com)',
        'from:(icims.com) OR from:(taleo.net) OR from:(successfactors.com)',
        'subject:(applied to OR you applied OR application for)',
        'subject:(next steps OR moving forward) (job OR role OR position OR opportunity)',
        'subject:micron application OR from:(micron.com)',
        'subject:(hiring OR recruiter) (application OR applied OR position)',
        'subject:(we have received OR confirmation) (application OR resume)',
      ];

      const allIds = new Set();
      for (const q of queries) {
        let pageToken = null;
        do {
          const params = { userId: 'me', q, maxResults: 50 };
          if (pageToken) params.pageToken = pageToken;
          const res = await window.gapi.client.gmail.users.messages.list(params);
          (res.result.messages || []).forEach(m => allIds.add(m.id));
          pageToken = res.result.nextPageToken;
        } while (pageToken && allIds.size < 500);
      }

      const ids = [...allIds];
      setProgress({ step: 'Fetching email content…', current: 0, total: ids.length });

      const emails = [];
      for (let i = 0; i < ids.length; i++) {
        setProgress({ step: 'Fetching email content…', current: i + 1, total: ids.length });
        try {
          const msg = await window.gapi.client.gmail.users.messages.get({
            userId: 'me', id: ids[i], format: 'metadata',
            metadataHeaders: ['Subject', 'From', 'Date'],
          });
          const hdrs = msg.result.payload?.headers || [];
          const get  = n => hdrs.find(h => h.name === n)?.value || '';
          emails.push({ subject: get('Subject'), from: get('From'), date: get('Date'), snippet: msg.result.snippet || '' });
        } catch(e) { /* skip */ }
      }

      setProgress({ step: 'Analyzing with Claude AI…', current: 0, total: emails.length });

      const BATCH = 15, results = [];
      for (let i = 0; i < emails.length; i += BATCH) {
        setProgress({ step: 'Analyzing with Claude AI…', current: Math.min(i + BATCH, emails.length), total: emails.length });
        const batch = emails.slice(i, i + BATCH);
        const prompt = `You are an expert at analyzing job application emails. For each email, determine if it is related to a job application process. Be generous — include application confirmations, recruiter outreach, interview invites, assessments, offers, and rejections.

For each email return a JSON object with:
- "isJobEmail": true/false
- "company": the company name (infer from From domain — micron.com = Micron Technology, travelers.com = Travelers, etc.)
- "role": the job title/position (extract from subject or snippet, can be null)
- "date": date in YYYY-MM-DD format
- "status": MUST be exactly one of "Applied", "Interview", "Offer", "Rejected", or null if isJobEmail is false

Return ONLY a JSON array of ${batch.length} objects (one per email, in order). No markdown, no explanation.

EMAILS:
${batch.map((e, idx) => `[${idx}]\nFrom: ${e.from}\nSubject: ${e.subject}\nDate: ${e.date}\nSnippet: ${e.snippet}`).join('\n\n---\n\n')}`;

        try {
          const resp = await fetch('https://api.anthropic.com/v1/messages', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'x-api-key': activeKey,
              'anthropic-version': '2023-06-01',
              'anthropic-dangerous-direct-browser-access': 'true',
            },
            body: JSON.stringify({
              model: 'claude-haiku-4-5-20251001',
              max_tokens: 2000,
              messages: [{ role: 'user', content: prompt }],
            }),
          });
          const data = await resp.json();
          if (data.error) throw new Error(data.error.message);
          const text   = data.content[0].text.trim().replace(/```json|```/g, '').trim();
          const parsed = JSON.parse(text);
          parsed.forEach((item, idx) => {
            if (item?.isJobEmail && item.company && item.status) {
              results.push({ ...item, id: `email-${i + idx}-${Date.now()}`, notes: '', url: '', salary: '', followUpDate: '' });
            }
          });
        } catch(e) { console.error('Claude batch error:', e); }
      }

      const RANK = { Offer: 4, Interview: 3, Applied: 2, Rejected: 1 };
      const merged = {};
      for (const r of results) {
        const key = `${(r.company || '').toLowerCase().trim()}__${(r.role || '').toLowerCase().trim()}`;
        if (!merged[key]) { merged[key] = { ...r }; }
        else {
          if ((RANK[r.status] || 0) > (RANK[merged[key].status] || 0)) merged[key].status = r.status;
          if (r.date && (!merged[key].date || r.date > merged[key].date)) merged[key].date = r.date;
        }
      }

      const final = Object.values(merged).sort((a, b) => (b.date || '').localeCompare(a.date || ''));
      setJobs(final);
      setProgress({ step: 'Done!', current: final.length, total: final.length });
    } catch(e) {
      setError('Error: ' + e.message);
    } finally {
      setLoading(false);
    }
  }, [claudeKey]);

  // ── Export CSV ──────────────────────────────────────────────────────────────
  const exportCSV = () => {
    const rows = filteredJobs.map(j =>
      `"${j.company||''}","${j.role||''}","${j.date||''}","${j.status||''}","${j.salary||''}","${j.url||''}","${(j.notes||'').replace(/"/g,'""')}","${j.followUpDate||''}"`
    );
    const blob = new Blob(['Company,Role,Date,Status,Salary,URL,Notes,Follow-up Date\n' + rows.join('\n')], { type: 'text/csv' });
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement('a'); a.href = url; a.download = 'job-applications.csv'; a.click();
    URL.revokeObjectURL(url);
  };

  // ── Chat ────────────────────────────────────────────────────────────────────
  const sendChat = async () => {
    if (!chatInput.trim() || chatLoading || jobs.length === 0) return;
    const activeKey = claudeKeyRef.current || claudeKey;
    const userMsg   = chatInput.trim();
    setChatInput('');
    setChatMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatLoading(true);

    const today = new Date().toISOString().split('T')[0];
    const summary = jobs.map(j =>
      `${j.company} | ${j.role || 'N/A'} | ${j.date || 'N/A'} | ${j.status}${j.followUpDate ? ` | follow-up: ${j.followUpDate}` : ''}${j.notes ? ` | notes: ${j.notes}` : ''}`
    ).join('\n');

    try {
      const resp = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': activeKey,
          'anthropic-version': '2023-06-01',
          'anthropic-dangerous-direct-browser-access': 'true',
        },
        body: JSON.stringify({
          model: 'claude-haiku-4-5-20251001',
          max_tokens: 600,
          messages: [{ role: 'user', content: `You are a helpful, concise job search assistant. Today is ${today}. The user has these tracked job applications:\n\n${summary}\n\nAnswer helpfully and specifically. Keep responses short.\n\nQuestion: ${userMsg}` }],
        }),
      });
      const data  = await resp.json();
      const reply = data.content?.[0]?.text || 'Sorry, could not get a response.';
      setChatMessages(prev => [...prev, { role: 'assistant', text: reply }]);
    } catch(e) {
      setChatMessages(prev => [...prev, { role: 'assistant', text: 'Error: ' + e.message }]);
    } finally {
      setChatLoading(false);
    }
  };

  // ── Computed ────────────────────────────────────────────────────────────────
  const today = new Date().toISOString().split('T')[0];

  const filteredJobs = useMemo(() => {
    let list = filter === 'All' ? jobs : jobs.filter(j => j.status === filter);
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      list = list.filter(j => (j.company || '').toLowerCase().includes(q) || (j.role || '').toLowerCase().includes(q));
    }
    return [...list].sort((a, b) => {
      if (sortBy === 'date')    return (b.date || '').localeCompare(a.date || '');
      if (sortBy === 'company') return (a.company || '').localeCompare(b.company || '');
      if (sortBy === 'status')  return (b.status || '').localeCompare(a.status || '');
      if (sortBy === 'followup')return (a.followUpDate || '9999').localeCompare(b.followUpDate || '9999');
      return 0;
    });
  }, [jobs, filter, searchQuery, sortBy]);

  const counts       = useMemo(() => jobs.reduce((acc, j) => { acc[j.status] = (acc[j.status] || 0) + 1; return acc; }, {}), [jobs]);
  const overdueCount = useMemo(() => jobs.filter(j => j.followUpDate && j.followUpDate <= today && j.status !== 'Rejected').length, [jobs, today]);
  const smartSuggestions = useMemo(() => getSmartSuggestions(jobs), [jobs]);

  // ── Render ──────────────────────────────────────────────────────────────────
  return (
    <div className="app">
      <div className="noise" />

      {/* ── Header ── */}
      <header className="header">
        <div className="header-left">
          <div className="logo-mark">JT</div>
          <div>
            <h1 className="app-title">Job Tracker</h1>
            <p className="app-sub">AI-powered application intelligence</p>
          </div>
        </div>
        <div className="header-right">
          {isSignedIn && jobs.length > 0 && (
            <div className="view-toggle">
              {[['table','☰ Table'], ['kanban','⊞ Board'], ['analytics','◈ Analytics']].map(([v, lbl]) => (
                <button key={v} className={`view-btn ${view === v ? 'active' : ''}`} onClick={() => setView(v)}>{lbl}</button>
              ))}
            </div>
          )}
          <button className="theme-btn" onClick={() => setTheme(t => t === 'dark' ? 'light' : 'dark')} title="Toggle theme">
            {theme === 'dark' ? '☀' : '☾'}
          </button>
          {isSignedIn && <button className="btn btn-ghost" onClick={signOut}>Sign Out</button>}
        </div>
      </header>

      {!isSignedIn ? (
        /* ── Landing ── */
        <div className="landing">
          <div className="landing-content">
            <div className="hero-badge">POWERED BY CLAUDE AI</div>
            <h2 className="hero-title">Your inbox.<br/>Your career.<br/><span className="accent">Organized.</span></h2>
            <p className="hero-desc">Connect your Gmail and let Claude AI scan your emails, extract every job application, and build you a live tracker — automatically.</p>

            <div className="setup-card">
              <label className="input-label">Anthropic API Key</label>
              <div className="input-row">
                <input type="password" className="text-input" placeholder="sk-ant-…" value={keyInput} onChange={e => setKeyInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && signIn()} />
              </div>
              <p className="input-hint">Used only in your browser — never sent to any server.</p>
              <button className="btn btn-primary" onClick={signIn} disabled={!gapiReady || !gisReady || !keyInput.trim()}>
                {(!gapiReady || !gisReady) ? 'Loading…' : 'Connect Gmail →'}
              </button>
              {error && <p className="error-msg">{error}</p>}
            </div>

            <div className="features">
              {[
                ['◎', 'Auto-Detects Applications', 'Scans Gmail and finds every confirmation email'],
                ['◈', 'Tracks Interviews',          'Identifies scheduling and assessment emails'],
                ['✕', 'Catches Rejections',         'Spots the "unfortunately" emails automatically'],
                ['◆', 'AI Chat Assistant',          'Ask anything about your job search in plain English'],
                ['⊞', 'Kanban Board View',          'Visual pipeline of your entire search'],
                ['◈', 'Charts & Analytics',         'Response rates, funnels, and monthly trends'],
              ].map(([icon, title, desc]) => (
                <div className="feature" key={title}>
                  <span className="feature-icon">{icon}</span>
                  <strong>{title}</strong>
                  <span>{desc}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      ) : (
        /* ── Dashboard ── */
        <div className="dashboard">

          {jobs.length === 0 && !loading && (
            <div className="scan-prompt">
              <div className="scan-icon">⟳</div>
              <h3>Ready to scan your inbox</h3>
              <p>Claude will search your Gmail for job-related emails and build your tracker.</p>
              <div className="scan-actions">
                <button className="btn btn-primary" onClick={fetchAndAnalyze}>Scan Emails with AI</button>
                <button className="btn btn-outline" onClick={() => setShowAddModal(true)}>+ Add Manually</button>
              </div>
            </div>
          )}

          {loading && (
            <div className="loading-card">
              <div className="spinner" />
              <p className="loading-step">{progress.step}</p>
              {progress.total > 0 && (
                <>
                  <div className="progress-bar"><div className="progress-fill" style={{ width: `${(progress.current / progress.total) * 100}%` }}/></div>
                  <p className="progress-text">{progress.current} / {progress.total}</p>
                </>
              )}
            </div>
          )}

          {error && <div className="error-banner">{error}</div>}

          {jobs.length > 0 && (
            <>
              {/* Stats Row */}
              <div className="stats-row">
                <div className="stat-card total">
                  <span className="stat-num">{jobs.length}</span>
                  <span className="stat-label">Total Applications</span>
                </div>
                {STATUSES.map(status => counts[status] ? (
                  <div key={status} className="stat-card clickable" style={{ borderColor: STATUS_CONFIG[status].color }}
                    onClick={() => { setFilter(status); setView('table'); }}>
                    <span className="stat-num" style={{ color: STATUS_CONFIG[status].color }}>{counts[status]}</span>
                    <span className="stat-label">{status}</span>
                  </div>
                ) : null)}
                {overdueCount > 0 && (
                  <div className="stat-card clickable" style={{ borderColor: '#FF5A5A' }} onClick={() => setSortBy('followup')}>
                    <span className="stat-num" style={{ color: '#FF5A5A' }}>{overdueCount}</span>
                    <span className="stat-label">Follow-ups Due</span>
                  </div>
                )}
              </div>

              {/* Toolbar (not shown in analytics view) */}
              {view !== 'analytics' && (
                <div className="toolbar">
                  <input type="text" className="search-input" placeholder="Search company or role…"
                    value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
                  <div className="filter-chips">
                    {['All', ...STATUSES].map(f => (
                      <button key={f} className={`chip ${filter === f ? 'active' : ''}`}
                        style={filter === f && f !== 'All' ? { background: STATUS_CONFIG[f]?.bg, color: STATUS_CONFIG[f]?.color, borderColor: STATUS_CONFIG[f]?.color } : {}}
                        onClick={() => setFilter(f)}>
                        {f !== 'All' && STATUS_CONFIG[f]?.icon + ' '}{f}
                      </button>
                    ))}
                  </div>
                  <div className="toolbar-right">
                    <select className="sort-select" value={sortBy} onChange={e => setSortBy(e.target.value)}>
                      <option value="date">Sort: Date</option>
                      <option value="company">Sort: Company</option>
                      <option value="status">Sort: Status</option>
                      <option value="followup">Sort: Follow-up</option>
                    </select>
                    <button className="btn btn-outline" onClick={() => setShowAddModal(true)}>+ Add Job</button>
                    <button className="btn btn-outline" onClick={exportCSV}>⬇ CSV</button>
                    <button className="btn btn-ghost" onClick={fetchAndAnalyze}>↺ Rescan</button>
                  </div>
                </div>
              )}

              {/* Views */}
              {view === 'table' && (
                <div className="table-wrap">
                  <table className="jobs-table">
                    <thead>
                      <tr>
                        <th>#</th><th>Company</th><th>Role</th><th>Date</th><th>Follow-up</th><th>Status</th><th></th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredJobs.map((job, idx) => {
                        const cfg = STATUS_CONFIG[job.status];
                        if (!cfg) return null;
                        const isOverdue = job.followUpDate && job.followUpDate <= today && job.status !== 'Rejected';
                        return (
                          <tr key={job.id} className={`job-row ${isOverdue ? 'overdue-row' : ''}`} onClick={() => setSelectedJob(job)}>
                            <td className="row-num">{idx + 1}</td>
                            <td className="company-cell">
                              {job.company || '—'}
                              {job.notes && <span className="notes-dot" title="Has notes">•</span>}
                            </td>
                            <td className="role-cell">{job.role || '—'}</td>
                            <td className="date-cell">{job.date || '—'}</td>
                            <td className="date-cell" onClick={e => e.stopPropagation()}>
                              {job.followUpDate
                                ? <span style={{ color: isOverdue ? '#FF5A5A' : 'var(--text2)' }}>{isOverdue ? '⚠ ' : ''}{job.followUpDate}</span>
                                : <span className="add-followup" onClick={() => setSelectedJob(job)}>+ Set</span>
                              }
                            </td>
                            <td onClick={e => e.stopPropagation()}>
                              <select
                                className="status-select-inline"
                                value={job.status}
                                onChange={e => updateJob(job.id, { status: e.target.value })}
                                style={{ color: cfg.color, background: cfg.bg, borderColor: cfg.color }}
                              >
                                {STATUSES.map(s => <option key={s} value={s}>{STATUS_CONFIG[s].icon} {s}</option>)}
                              </select>
                            </td>
                            <td className="row-action-cell" onClick={e => e.stopPropagation()}>
                              <button className="icon-btn" onClick={() => setSelectedJob(job)} title="View details">→</button>
                            </td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                  {filteredJobs.length === 0 && <div className="empty-state">No applications match this filter.</div>}
                </div>
              )}

              {view === 'kanban' && <KanbanBoard jobs={filteredJobs} onCardClick={setSelectedJob} />}
              {view === 'analytics' && <AnalyticsView jobs={jobs} />}
            </>
          )}
        </div>
      )}

      {/* ── Modals & Panels ── */}
      {showAddModal && <AddJobModal onClose={() => setShowAddModal(false)} onAdd={addJobManually} />}

      {selectedJob && (
        <div className="panel-overlay" onClick={e => e.target === e.currentTarget && setSelectedJob(null)}>
          <JobDetailPanel job={selectedJob} onClose={() => setSelectedJob(null)} onUpdate={updateJob} onDelete={deleteJob} />
        </div>
      )}

      {/* ── AI Chat ── */}
      {isSignedIn && jobs.length > 0 && (
        <>
          <button className="chat-fab" onClick={() => setChatOpen(o => !o)}>
            {chatOpen ? '✕' : '◆'}
            {!chatOpen && <span className="chat-fab-label">Ask AI</span>}
          </button>

          {chatOpen && (
            <div className="chat-panel">
              <div className="chat-header">
                <div className="chat-header-left">
                  <div className="chat-avatar">◆</div>
                  <div>
                    <div className="chat-title">Job Search Assistant</div>
                    <div className="chat-sub">Analyzing {jobs.length} applications</div>
                  </div>
                </div>
                <button className="btn btn-ghost" onClick={() => setChatOpen(false)}>✕</button>
              </div>

              <div className="chat-messages">
                {chatMessages.map((msg, i) => (
                  <div key={i} className={`chat-msg ${msg.role}`}>
                    <div className="chat-bubble">{msg.text}</div>
                  </div>
                ))}
                {chatLoading && (
                  <div className="chat-msg assistant">
                    <div className="chat-bubble chat-typing"><span/><span/><span/></div>
                  </div>
                )}
                <div ref={chatEndRef} />
              </div>

              <div className="chat-suggestions">
                {smartSuggestions.map(s => (
                  <button key={s} className="suggestion-chip" onClick={() => setChatInput(s)}>{s}</button>
                ))}
              </div>

              <div className="chat-input-row">
                <input
                  className="chat-input"
                  placeholder="Ask about your applications…"
                  value={chatInput}
                  onChange={e => setChatInput(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && sendChat()}
                />
                <button className="chat-send" onClick={sendChat} disabled={chatLoading || !chatInput.trim()}>→</button>
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
}
